var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_B","text":{"KOREA":"도, 도시가 사라졌어.","JPN":"と、都市が消えた。","ENG":"Th-the city disappeared.","TWN":"城，城市消失了。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"……그 침식체를 어떻게든 막아낸 건가.","JPN":"……あの侵食体をなんとか追い払ったのか。","ENG":"...Did she really stop that C.O. somehow?","TWN":"……總算是擋下了那個侵蝕體。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"압도적인 차이였다.","JPN":"圧倒的な力だった。","ENG":"It was overwhelming power.","TWN":"實力差距太大了。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"저 여자가 없었다면…… 우린 분명 살아남지 못했겠지.","JPN":"あの女がいなければ……俺たちは間違いなく全滅だった。","ENG":"If it weren't for her... we wouldn't be alive right now.","TWN":"如果沒有那個女人……我們肯定沒辦法活的。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"아합! 아합은 어디있지?","JPN":"アハブ！　アハブはどこにいる？","ENG":"Ahab! Where are you?","TWN":"亞哈！亞哈在哪？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"에스타크의 포격이 통하지 않은 걸 보고 바로 도망친 것 같다.","JPN":"エスタークの砲撃が効かないとわかった途端、逃げやがったらしい。","ENG":"I think he fled after seeing that the Estaque's bombardment didn't work.","TWN":"他看到艾斯塔克沒效，就立刻逃跑了吧。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"망할 새끼. 그렇게 자신만만해하더니.","JPN":"クソ野郎。あんな自信満々だったくせに。","ENG":"That bastard. I should've known when he looked too confident.","TWN":"混帳東西，之前還一副胸有成竹的樣子。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"제대로 당했어.","JPN":"コテンパンにやられたな。","ENG":"He tricked us.","TWN":"被他給擺了一道。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"로터스에선 아무도 믿으면 안 되는 법인데, 젠장.","JPN":"ロータスでは誰も信じるなということを忘れていたぜ、くそぉ。","ENG":"You can't trust anyone in Lotus, crap.","TWN":"該死的，在洛德斯果然不該相信任何人。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"이, 이봐. 미안하게 됐어. 우리도 일이 이렇게 될 줄은 몰랐다고.","JPN":"お、おい、すまなかった。俺たちだって、まさかこうなるとは思わなかった。","ENG":"H-hey. Sorry about all this. We didn't know either that it'd turn out this way.","TWN":"那個，很抱歉，我們也沒想到事情會變成這樣。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"저런 침식체는 처음 봤단 말이야.","JPN":"あんな侵食体は見たこともなかったんだ。","ENG":"It's my first time seeing a C.O. like that.","TWN":"我還是第一次見到那種侵蝕體。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"당신 같이 강한 카운터도 어쩌지 못하는 걸 우리가 할 수는 없으니까…….","JPN":"あんたのような強いカウンターでもどうにもならない相手に、俺たちが敵うわけないからな……","ENG":"And there's nothing we can do when a strong Counter like you can't either...","TWN":"像連你這麼強的制裁者都無能為力，更別說我們……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"……알고 있었다. 너희의 힘으로는 어림도 없다는 걸.","JPN":"……わかっている。君たちじゃどうにもならないってことは。","ENG":"...I knew that it was beyond your capabilities.","TWN":"……我早就知道，以你們的能力是不可能成功的。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"결국 이번에도 놈을 죽이지 못했어.","JPN":"結局、今回も奴を殺せなかった。","ENG":"In the end, I wasn't able to kill it this time.","TWN":"結果這次也沒能殺掉那傢伙。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"아합은 침식체가 날 찾아올 거란 걸 알고 있었나?","JPN":"そもそもアハブは、私が侵食体を惹き付けるだろうと最初から想定していた？","ENG":"Did Ahab know that the C.O. would come after me?","TWN":"亞哈知道侵蝕體會衝著我來嗎？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그렇기에 에스타크의 위력을 잘 알고 있는 나에게 의도적으로 접근한 걸지도.","JPN":"エスタークの威力をよく知っている私に近づいたのも、意図的なものだったのかもしれない。","ENG":"Perhaps that's why he deliberately approached me, who knew Estaque's firepower from the start.","TWN":"而且知道我熟悉艾斯塔克的威力，就用這一點來刻意接近我。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그렇다면…… 아합은 나에 대해 알고 있던 것일까?","JPN":"つまり……アハブは私のことを以前から知っていた？","ENG":"Then... does that mean he knows something about me?","TWN":"這表示……他知道關於我的事？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"서로의 욕심이 화를 부른 거다. 나도, 너희들도. 그 아합이란 자의 꼬임에 휘둘려서.","JPN":"今回の失態は我々の身から出たさびだ。お互いの欲を、あのアハブという者の思惑に利用れてしまった。","ENG":"Our greed is what caused this disaster. You and I were fooled by Ahab.","TWN":"是我們的私慾引來的災禍。不僅是我，還有你們，都掉入亞哈設下的局裡。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그러니…….","JPN":"だから……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_B","text":{"KOREA":"우, 우리가 그 새끼를 찾아볼게!","JPN":"お、俺たちが奴を捜索してみるよ！","ENG":"W-we'll go look for that bastard!","TWN":"我，我們會找到那個臭傢伙的！"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_B","text":{"KOREA":"그 아합이란 새끼도 분명 사막을 뒤지면 흔적이라도 나올 거야!","JPN":"アハブだって、砂漠をくまなく探せば、痕跡ぐらい残しているはずさ！","ENG":"I'm sure if we search the desert, we'll find traces of him!","TWN":"就算要翻遍這座沙漠也會把他找出來的！"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_B","text":{"KOREA":"그 고래 같은 녀석도 어떻게든 처리할게!","JPN":"あのクジラみたいな奴も、なんとかしてみるぜ！","ENG":"We'll also deal with that whale somehow!","TWN":"還，還有那隻鯨魚我們也會想辦法處理的！"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_B","text":{"KOREA":"혼자 움직이는 것보다는 여럿이서 움직이는 게 낫잖아? 안 그래?","JPN":"一人より、集団で動いた方がいいだろう？　なぁ？","ENG":"Won't it be better to move as a group than alone?","TWN":"俗話說團結力量大，你說對吧？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"}}}}]`);export{e as default};